import{_ as e,o as n,c as i,af as s}from"./chunks/framework.BSym9njW.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/01-deploy/minicpm-o/index.md","filePath":"zh/01-deploy/minicpm-o/index.md","lastUpdated":1782372845000}'),l={name:"zh/01-deploy/minicpm-o/index.md"};function r(o,a,t,p,h,m){return n(),i("div",null,[...a[0]||(a[0]=[s(`<div align="center"><h1>MiniCPM-o 4.5 部署</h1><strong>🎙️ 在 AMD GPU 上运行全模态大模型</strong></div><div align="center"><p><em>语音 · 视觉 · TTS · 全双工对话 · ROCm 7+ · llama.cpp-omni</em></p><p><a href="/hello-rocm/zh/">返回主页</a> · <a href="/hello-rocm/01-deploy/minicpm-o/">English</a> · <a href="/hello-rocm/zh/01-deploy/">返回部署总览</a></p></div><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>  <strong>MiniCPM-o 4.5</strong> 是面壁智能（OpenBMB）推出的端侧全模态大模型，支持<strong>文本、语音输入 + 语音输出</strong>（TTS）以及<strong>图像理解</strong>，并可通过 Omni 全双工模式实现类电话的实时交互——无需 NVIDIA GPU，在 AMD ROCm 上同样可以完整运行。</p><p>  本模块基于 OpenBMB 官方开源的 <a href="https://github.com/tc-mb/llama.cpp-omni" target="_blank" rel="noreferrer">llama.cpp-omni</a> 推理引擎和 <a href="https://github.com/OpenBMB/MiniCPM-o-Demo" target="_blank" rel="noreferrer"><code>OpenBMB/MiniCPM-o-Demo</code></a> 演示仓库（<code>Comni</code> 分支），在 <strong>AMD Ryzen AI MAX+ 395（gfx1151 / Strix Halo APU）</strong> 上验证通过，同样适用于其他支持 ROCm 的 AMD GPU。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>01-Deploy/minicpm-o/</span></span>
<span class="line"><span>├── minicpm-o-model.md               # MiniCPM-o 4.5 模型介绍</span></span>
<span class="line"><span>├── llamacpp-omni-rocm7-deploy.md    # llama.cpp-omni CLI 推理部署</span></span>
<span class="line"><span>└── webdemo-rocm7-deploy.md          # MiniCPM-o Web Demo 全双工部署</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><hr><h2 id="教程列表" tabindex="-1">教程列表 <a class="header-anchor" href="#教程列表" aria-label="Permalink to &quot;教程列表&quot;">​</a></h2><h3 id="minicpm-o-4-5-模型介绍" tabindex="-1">MiniCPM-o 4.5 模型介绍 <a class="header-anchor" href="#minicpm-o-4-5-模型介绍" aria-label="Permalink to &quot;MiniCPM-o 4.5 模型介绍&quot;">​</a></h3><p>  了解 MiniCPM-o 4.5 的全模态架构——语音输入、视觉编码、TTS 语音合成与全双工对话设计。读完后可清楚知道需要哪些 GGUF 子模型文件，以及不同 GPU 的显存要求。</p><ul><li><strong>适合人群</strong>：希望在部署前了解模型架构的读者</li><li><strong>难度等级</strong>：⭐</li><li><strong>预计时间</strong>：15 分钟</li></ul><p>📖 <a href="./minicpm-o-model">阅读 MiniCPM-o 4.5 模型介绍</a></p><hr><h3 id="llama-cpp-omni-cli-零基础部署" tabindex="-1">llama.cpp-omni CLI 零基础部署 <a class="header-anchor" href="#llama-cpp-omni-cli-零基础部署" aria-label="Permalink to &quot;llama.cpp-omni CLI 零基础部署&quot;">​</a></h3><p>  使用 llama.cpp-omni 推理引擎，在 AMD GPU 上编译并运行 MiniCPM-o 4.5。本教程覆盖 HIP 编译、GGUF 模型下载、音频输入测试和 TTS 语音输出，让你用命令行跑通全模态推理。</p><ul><li><strong>适合人群</strong>：希望轻量验证推理能力、或为 Web Demo 准备推理后端的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：2 小时（含模型下载）</li></ul><p>📖 <a href="./llamacpp-omni-rocm7-deploy">开始学习 llama.cpp-omni 部署教程</a></p><hr><h3 id="minicpm-o-web-demo-全双工部署" tabindex="-1">MiniCPM-o Web Demo 全双工部署 <a class="header-anchor" href="#minicpm-o-web-demo-全双工部署" aria-label="Permalink to &quot;MiniCPM-o Web Demo 全双工部署&quot;">​</a></h3><p>  基于 <code>OpenBMB/MiniCPM-o-Demo</code>（<code>Comni</code> 分支），在 AMD GPU 上搭建完整的 Web Demo，支持<strong>轮询对话 / 半双工 / Omni 全双工 / 纯语音全双工</strong>四种交互模式，在浏览器中即可与模型语音+视频实时对话。前置条件：已完成 llama.cpp-omni 编译。</p><ul><li><strong>适合人群</strong>：希望搭建完整交互演示的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：1 小时（推理后端已就绪的情况下）</li></ul><p>📖 <a href="./webdemo-rocm7-deploy">开始学习 Web Demo 全双工部署</a></p><hr><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>最低配置</th><th>推荐配置</th></tr></thead><tbody><tr><td>文本推理（仅 LLM）</td><td>8 GB 显存</td><td>—</td></tr><tr><td>语音输入（音频编码器）</td><td>12 GB 显存</td><td>—</td></tr><tr><td>完整全模态（LLM + 视觉 + 音频 + TTS）</td><td><strong>16 GB 显存</strong></td><td>64 GB 统一内存（Strix Halo APU）</td></tr></tbody></table><blockquote><p>AMD Ryzen AI MAX+ 395 / 890M 系列的统一内存架构非常适合 MiniCPM-o——64 GB 统一内存可将全部 GGUF 子模型（~8.3 GB）完整载入 GPU。</p></blockquote><h3 id="软件要求" tabindex="-1">软件要求 <a class="header-anchor" href="#软件要求" aria-label="Permalink to &quot;软件要求&quot;">​</a></h3><ul><li>操作系统：Linux（Ubuntu 22.04 / 24.04）</li><li>ROCm 7.10.0 或更高版本（系统安装）</li><li>CMake 3.21+，GCC / Clang（用于 HIP 编译）</li><li>Python 3.10+（Web Demo 依赖）</li></ul><h3 id="本教程测试环境" tabindex="-1">本教程测试环境 <a class="header-anchor" href="#本教程测试环境" aria-label="Permalink to &quot;本教程测试环境&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>硬件：AMD Ryzen AI MAX+ PRO 395 / Radeon™ 890M（Strix Halo）</span></span>
<span class="line"><span>架构：gfx1151</span></span>
<span class="line"><span>统一内存：64 GB（全部可作 VRAM 使用）</span></span>
<span class="line"><span>ROCm：7.12.0（系统）+ TheRock 7.12.0a alpha（修复 Tensile）</span></span>
<span class="line"><span>OS：Ubuntu 24.04</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details><summary>Q: MiniCPM-o 4.5 和普通 LLM 有什么区别，为什么不能直接用 vLLM / Ollama 部署？</summary><p>MiniCPM-o 4.5 是全模态模型，包含独立的<strong>语音编码器</strong>、<strong>视觉编码器</strong>、<strong>TTS 语音合成</strong>（token2wav）等多个子模块，这些模块目前尚未被主流推理框架原生支持。llama.cpp-omni 是专门为此模型设计的推理引擎 fork，可以同时加载并调度这些子模型。</p></details><details><summary>Q: gfx1151（Strix Halo）需要特殊处理吗？</summary><p>是的。gfx1151 是 2025 年底推出的新架构，系统 <code>/opt/rocm</code> 内的 rocBLAS Tensile 库<strong>尚不包含 gfx1151 的完整 GEMM 内核</strong>，会导致推理时崩溃（<code>hipErrorInvalidImage</code>）。解决方法是安装 TheRock 7.12.0a alpha SDK 并在运行时指向其 rocBLAS 库目录——详见 <a href="./llamacpp-omni-rocm7-deploy">llama.cpp-omni 部署教程</a>。</p><p>其他 AMD GPU（如 gfx1100 / RX 7900 XTX、gfx1150 / RX 9070 XT 等）不受此问题影响，可直接使用系统 rocBLAS。</p></details><details><summary>Q: 如何确认我的 AMD GPU 架构（gfx 编号）？</summary><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">rocminfo</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> | </span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">grep</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -A</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;"> 5</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> &quot;Agent [0-9]&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> | </span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">grep</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -E</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> &quot;Name|gfx&quot;</span></span>
<span class="line"><span style="--shiki-light:#008000;--shiki-dark:#6A9955;"># 或</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">amd-smi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><hr><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://github.com/OpenBMB/MiniCPM-o" target="_blank" rel="noreferrer">MiniCPM-o 官方仓库（OpenBMB）</a></li><li><a href="https://github.com/tc-mb/llama.cpp-omni" target="_blank" rel="noreferrer">llama.cpp-omni</a></li><li><a href="https://github.com/OpenBMB/MiniCPM-o-Demo" target="_blank" rel="noreferrer">MiniCPM-o-Demo 官方仓库</a></li><li><a href="https://www.modelscope.cn/models/OpenBMB/MiniCPM-o-4_5-gguf" target="_blank" rel="noreferrer">MiniCPM-o-4_5-gguf（ModelScope）</a></li><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm 官方文档</a></li><li><a href="https://rocm.nightlies.amd.com/v2/gfx1151/" target="_blank" rel="noreferrer">TheRock Nightly SDK（gfx1151 修复）</a></li></ul><hr><div align="center"><p><strong>欢迎贡献更多部署教程！</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">提交 Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">提交 PR</a></p></div>`,41)])])}const g=e(l,[["render",r]]);export{c as __pageData,g as default};
